-- ============================================================================
-- 明示的にIDを指定してINSERTしたテーブルのシーケンスを最大IDに合わせる
-- （合わせないと次のINSERTでID衝突が発生する）
-- ============================================================================
SELECT setval('product_id_seq', (SELECT MAX(id) FROM product));
SELECT setval('category_id_seq', (SELECT MAX(id) FROM category));
SELECT setval('customer_order_id_seq', (SELECT MAX(id) FROM customer_order));
SELECT setval('customer_order_detail_id_seq', (SELECT MAX(id) FROM customer_order_detail));
